#include <bits/stdc++.h>
using namespace std;
int a,b,p,f[100005],prime[100005],sum,ans;
bool is_prime[100005];
void shai(){
    for(int i=2;i<=b;i++){
        if(!is_prime[i])
            prime[++sum]=i;
        for(int j=1;j<=sum && prime[j]*i<=b;j++){
            is_prime[i*prime[j]]=1;
            if(i%prime[j]==0)
                break;
        }
    }
}
int father(int x){
    return (f[x]==x?x:f[x]=father(f[x]));
}
void merge(int x,int y){
    int fx=father(x),fy=father(y);
    if(fx!=fy)
        ans--,f[fy]=fx;
}
int main(){
    scanf("%d%d%d",&a,&b,&p);
    shai();
    for(int i=a;i<=b;i++)
        f[i]=i;
    ans=b-a+1;
    for(int i=1;i<=sum;i++){
        if(prime[i]>=p){
            int cnt=(a+prime[i]-1)/prime[i]*prime[i];
            while(cnt+prime[i]<=b)
                merge(cnt,cnt+prime[i]),cnt+=prime[i];
        }
    }
    printf("%d",ans);
    return 0;
}
